import Seo from '@/component/seo'
import SudokuGame from '@kyokuya/react-game-sudoku'
import { graphql } from 'gatsby'
import React from 'react'
import './style.styl'

export interface SudokuPageProps {
  data: {
    site: {
      siteMetadata: {
        author: any
        copyright: { date: string }
      }
    }
  }
}

const SudokuPage: React.FC<SudokuPageProps> = (props: SudokuPageProps) => {
  const { author, copyright } = props.data.site.siteMetadata

  return (
    <div className="page-game-sudoku">
      <Seo title="Sudoku Game" />
      <header>
        <h1>Sudoku Game</h1>
      </header>
      <main>
        <SudokuGame />
      </main>
      <footer>
        <span>
          © {copyright.date} {author.name}
        </span>
        <span>{author.motto}</span>
      </footer>
    </div>
  )
}

export default SudokuPage

export const query = void graphql`
query SudokuGamePageQuery {
  site {
    siteMetadata {
      author {
        name
        motto
        github
        rss
        home
      }
      copyright {
        date
      }
      title
      description
    }
  }
}
`
