import { useState } from 'react'
import { GameRunningState } from '../constant'

/**
 * Time usage record.
 */
interface RecordTime {
  /**
   * Cumulative use of time.
   */
  usedTime: number
  /**
   * Timestamp of the last time the timer started.
   */
  lastStartTime: number
}

/**
 * Return elapsed time (milliseconds) in game.
 * @param state
 * @returns
 */
export function useElapsedTime(state: GameRunningState): number {
  const [{ usedTime, lastStartTime }, setRecordTime] = useState<RecordTime>({
    usedTime: 0,
    lastStartTime: -1,
  })

  switch (state) {
    case GameRunningState.PENDING: {
      if (usedTime !== 0 || lastStartTime !== -1) {
        setRecordTime({ usedTime: 0, lastStartTime: -1 })
      }
      return 0
    }
    case GameRunningState.RUNNING: {
      if (lastStartTime === -1) {
        setRecordTime({ usedTime, lastStartTime: Date.now() })
        return usedTime
      }
      return usedTime + Date.now() - lastStartTime
    }
    case GameRunningState.PAUSED: {
      if (lastStartTime !== -1) {
        const nextUsedTime = usedTime + Date.now() - lastStartTime
        setRecordTime({ usedTime: nextUsedTime, lastStartTime: -1 })
        return nextUsedTime
      }
      return usedTime
    }
    case GameRunningState.FINISHED: {
      if (lastStartTime !== -1) {
        const nextUsedTime = usedTime + Date.now() - lastStartTime
        setRecordTime({ usedTime: nextUsedTime, lastStartTime: -1 })
        return nextUsedTime
      }
      return usedTime
    }
    default:
      throw new TypeError(
        `[usedRecordTime] expect a GameRunningState, but got (${state})`,
      )
  }
}
