import {
  Button,
  Dialog,
  DialogActions,
  DialogContent,
  TextField,
} from '@material-ui/core'
import React, { useEffect, useState } from 'react'

export interface SudokuInputComponentProps {
  /**
   * Initial value.
   */
  initialValue: string
  /**
   * Whether to show the dialog.
   */
  visible: boolean
  /**
   *
   */
  digitalBase: number
  /**
   * Input label.
   */
  label?: string
  /**
   * Triggered on canceled.
   */
  onCancel(): void
  /**
   * Triggered on confirmed.
   * @param value
   */
  onConfirm(value: string): void
}

export function SudokuInputComponent(
  props: SudokuInputComponentProps,
): React.ReactElement {
  const { initialValue, visible, digitalBase, label, onCancel, onConfirm } =
    props
  const [value, setValue] = useState<string>(initialValue)
  useEffect(() => setValue(initialValue), [initialValue, visible])

  return (
    <Dialog
      open={visible}
      onClose={onCancel}
      aria-labelledby="form-dialog-title"
    >
      <DialogContent>
        <TextField
          autoFocus={true}
          margin="dense"
          label={label}
          type={digitalBase <= 10 ? 'number' : 'input'}
          fullWidth={true}
          value={value}
          onChange={e => setValue(e.target.value)}
          onFocus={e => e.target.select()}
          onKeyDown={e => {
            if (e.key === 'Enter') onConfirm(value)
          }}
        />
      </DialogContent>
      <DialogActions>
        <Button color="default" onClick={onCancel}>
          Cancel
        </Button>
        <Button color="primary" onClick={() => onConfirm(value)}>
          Confirm
        </Button>
      </DialogActions>
    </Dialog>
  )
}

export default SudokuInputComponent
